import{_ as r,o as t,c as o,a0 as s}from"./chunks/framework.jwovEGr5.js";const a="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR4nGMAAQAABQABDQottAAAAABJRU5ErkJggg==",n="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR4nGMAAQAABQABDQottAAAAABJRU5ErkJggg==",i="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR4nGMAAQAABQABDQottAAAAABJRU5ErkJggg==",l="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR4nGMAAQAABQABDQottAAAAABJRU5ErkJggg==",p=JSON.parse('{"title":"Reading the Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/dashboard-tour.md","filePath":"getting-started/dashboard-tour.md"}'),d={name:"getting-started/dashboard-tour.md"};function h(A,e,g,m,c,u){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="reading-the-dashboard" tabindex="-1">Reading the Dashboard <a class="header-anchor" href="#reading-the-dashboard" aria-label="Permalink to &quot;Reading the Dashboard&quot;">​</a></h1><p>The dashboard is your home screen — the first thing you see after logging in. It&#39;s a summary: recent activity, key numbers, and charts for the part of the platform you&#39;re responsible for. What appears depends on your <a href="./../roles/overview.html">role</a> and your current <a href="./glossary.html#context-context-banner">context</a>.</p><h2 id="what-s-on-the-dashboard" tabindex="-1">What&#39;s on the dashboard <a class="header-anchor" href="#what-s-on-the-dashboard" aria-label="Permalink to &quot;What&#39;s on the dashboard&quot;">​</a></h2><p>Most dashboards include some mix of these:</p><ul><li><strong>Headline stats</strong> — quick counts and figures (players, events, recent results, and similar) for your kingdom or alliance.</li><li><strong>Kingdom Pulse</strong> — a snapshot of how your kingdom or alliance is doing overall: activity and momentum at a glance.</li><li><strong>Charts</strong> — visual trends drawn from your recorded results, so you can spot who&#39;s rising, falling, or missing.</li><li><strong>KvK Prep alerts</strong> — reminders and warnings tied to Kingdom‑vs‑Kingdom preparation, when relevant, so nothing slips before a big event.</li></ul><p><img src="'+a+'" alt="Supreme admin dashboard"></p><h2 id="how-the-dashboard-changes-by-role" tabindex="-1">How the dashboard changes by role <a class="header-anchor" href="#how-the-dashboard-changes-by-role" aria-label="Permalink to &quot;How the dashboard changes by role&quot;">​</a></h2><p>The dashboard shows you <em>your</em> slice of the platform — no more, no less:</p><ul><li><strong>Supreme Admin</strong> — a platform‑wide view spanning all kingdoms. <img src="'+a+'" alt="Supreme admin dashboard"></li><li><strong>King</strong> — the whole of <em>their</em> kingdom: its alliances, players, and events. <img src="'+n+'" alt="King dashboard"></li><li><strong>Alliance Leader / Co‑Leader</strong> — <em>their</em> alliance&#39;s players, events, and trends. <img src="'+i+'" alt="Leader dashboard"></li><li><strong>Alliance Player</strong> — a read‑only view of the alliance data they&#39;re allowed to see. <img src="'+l+'" alt="Viewer dashboard"></li></ul><p>If your dashboard looks emptier than a colleague&#39;s, it usually just means your role has a narrower scope — not that data is missing.</p><h2 id="reading-it-well" tabindex="-1">Reading it well <a class="header-anchor" href="#reading-it-well" aria-label="Permalink to &quot;Reading it well&quot;">​</a></h2><ul><li><strong>Numbers feel off?</strong> Check your <a href="./navigating.html#the-context-banner--knowing-where-you-are">context banner</a> first. The dashboard only reflects your current kingdom/alliance.</li><li><strong>A chart is empty?</strong> There may simply be no recorded results yet for that period. Once events are imported or entered, charts fill in.</li><li><strong>Want more detail?</strong> The dashboard is a summary. Use <strong>Analytics</strong>, <strong>Players</strong>, and <strong>Event Instances</strong> in the sidebar to drill in.</li></ul><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="./navigating.html">Finding Your Way Around</a> — the sidebar and top bar.</li><li><a href="./../roles/overview.html">Roles Explained</a> — why your view differs from someone else&#39;s.</li></ul>',14)])])}const f=r(d,[["render",h]]);export{p as __pageData,f as default};
